  1→import { useState } from 'react';
  2→import { useSketch } from '../app/SketchProvider';
  3→import { useSketchEditor } from '../app/SketchEditorProvider';
  4→import { MATERIAL_OPTIONS, LEG_PROFILE_OPTIONS, FRAME_AXIS_OPTIONS } from '../domain/partDefaults';
  5→import { clampDimension } from '../domain/validation';
  6→import { createConstraint, CONSTRAINT_TYPES, ANCHOR_OPTIONS } from '../domain/constraintModels';
  7→import { applyDimensionValueToPart, bindDimensionToPart } from '../domain/dimensionBinding';
  8→import { generateAssemblySheet, generateObjectSheet } from '../sheets/sketchSheetTemplates';
  9→import { exportActiveSheetAsPdf, exportActiveSheetAsPng } from '@/export/sheetExport';
 10→import { getTemplate } from '../domain/templates/templateRegistry';
 11→import TemplateParamsForm from './TemplateParamsForm';
