 13→
 14→function NumberInput({ label, value, onChange, suffix = 'mm', step = 1, readOnly = false }) {
 15→  return (
 16→    <label className={styles.field}>
 17→      <span className={styles.fieldLabel}>{label}</span>
 18→      <div className={styles.fieldInput}>
 19→        <input
 20→          type="number"
 21→          value={Math.round(value)}
 22→          step={step}
 23→          readOnly={readOnly}
 24→          onChange={(e) => {
 25→            const v = parseFloat(e.target.value);
 26→            if (!isNaN(v)) onChange(v);
 27→          }}
 28→          onBlur={(e) => {
 29→            if (readOnly) return;
 30→            const v = parseFloat(e.target.value);
 31→            if (!isNaN(v)) {
 32→              const clamped = clampDimension(v);
 33→              if (clamped !== v) onChange(clamped);
 34→            }
 35→          }}
 36→          className={styles.numberInput}
 37→        />
 38→        {suffix && <span className={styles.suffix}>{suffix}</span>}
 39→      </div>
 40→    </label>
 41→  );
 42→}
 43→
 44→function SelectInput({ label, value, options, onChange }) {
 45→  return (
 46→    <label className={styles.field}>
 47→      <span className={styles.fieldLabel}>{label}</span>
 48→      <select
 49→        value={value}
 50→        onChange={(e) => onChange(e.target.value)}
 51→        className={styles.selectInput}
 52→      >
 53→        {options.map((opt) => (
 54→          <option key={opt.value} value={opt.value}>{opt.label}</option>
 55→        ))}
 56→      </select>
 57→    </label>
 58→  );
 59→}
 60→
 61→function TextInput({ label, value, onChange }) {
 62→  return (
 63→    <label className={styles.field}>
 64→      <span className={styles.fieldLabel}>{label}</span>
 65→      <input
 66→        type="text"
 67→        value={value}
 68→        onChange={(e) => onChange(e.target.value)}
 69→        className={styles.textInput}
 70→      />
 71→    </label>
