112→    <>
113→      <NumberInput label="Width" value={part.width} onChange={(v) => onUpdate({ width: v })} />
114→      <NumberInput label="Height" value={part.height} onChange={(v) => onUpdate({ height: v })} />
115→      <NumberInput label="Length" value={part.length} onChange={(v) => onUpdate({ length: v })} />
