131→function HoleFields({ part, onUpdate }) {
132→  return (
133→    <>
134→      <NumberInput label="Diameter" value={part.diameter} onChange={(v) => onUpdate({ diameter: v })} />
135→      <NumberInput label="Depth" value={part.depth} onChange={(v) => onUpdate({ depth: v })} />
136→    </>
