357→function SheetProperties({ sheet, project, dispatch }) {
358→  const handleUpdate = (changes) => {
359→    dispatch({ type: 'SKETCH_SHEET_UPDATE', sheet: { id: sheet.id, ...changes } });
360→  };
361→
362→  return (
363→    <>
364→      <TextInput label="Title" value={sheet.title || ''} onChange={(v) => handleUpdate({ title: v })} />
365→      <TextInput label="Number" value={sheet.number || ''} onChange={(v) => handleUpdate({ number: v })} />
366→      <TextInput label="Drawing Name" value={sheet.drawingName || ''} onChange={(v) => handleUpdate({ drawingName: v })} />
367→      <SelectInput
368→        label="Paper Size"
369→        value={sheet.paperSize || 'A3_LANDSCAPE'}
370→        options={PAPER_SIZE_OPTIONS}
371→        onChange={(v) => handleUpdate({ paperSize: v })}
372→      />
373→      <TextInput label="Scale Label" value={sheet.scaleLabel || ''} onChange={(v) => handleUpdate({ scaleLabel: v })} />
374→    </>
375→  );
376→}
