378→function SheetViewportProperties({ viewport, sheet, project, dispatch }) {
379→  const objects = project.objects || [];
380→  const assemblies = project.assemblies || [];
381→  const selectableParts = project.parts.filter((p) => p.type !== 'dimension');
382→
383→  const handleUpdate = (changes) => {
384→    dispatch({
385→      type: 'SKETCH_SHEET_VIEWPORT_UPDATE',
386→      sheetId: sheet.id,
387→      viewport: { id: viewport.id, ...changes },
388→    });
389→  };
390→
391→  const handleDelete = () => {
392→    dispatch({ type: 'SKETCH_SHEET_VIEWPORT_DELETE', sheetId: sheet.id, viewportId: viewport.id });
393→  };
394→
395→  return (
396→    <>
397→      <TextInput label="Title" value={viewport.title || ''} onChange={(v) => handleUpdate({ title: v })} />
398→      <SelectInput
399→        label="Source View"
400→        value={viewport.sourceView || 'sketch_object_top'}
401→        options={VIEWPORT_SOURCE_OPTIONS}
402→        onChange={(v) => handleUpdate({ sourceView: v })}
403→      />
404→      {viewport.sourceView?.startsWith('sketch_object') && (
405→        <SelectInput
406→          label="Object"
407→          value={viewport.sourceRefId || ''}
408→          options={[
409→            { value: '', label: 'All Objects' },
410→            ...objects.map((object) => ({ value: object.id, label: object.name })),
411→          ]}
412→          onChange={(v) => handleUpdate({ sourceRefId: v || null, sourceObjectId: v || null })}
413→        />
414→      )}
415→      {viewport.sourceView?.startsWith('sketch_assembly') && (
416→        <SelectInput
417→          label="Assembly"
418→          value={viewport.sourceRefId || ''}
419→          options={[
420→            { value: '', label: 'All Parts' },
421→            ...assemblies.map((a) => ({ value: a.id, label: a.name })),
422→          ]}
423→          onChange={(v) => handleUpdate({ sourceRefId: v || null })}
424→        />
425→      )}
426→      {viewport.sourceView === 'sketch_part_detail' && (
427→        <SelectInput
428→          label="Part"
429→          value={viewport.sourceRefId || ''}
430→          options={[
431→            { value: '', label: 'Select part...' },
432→            ...selectableParts.map((p) => ({ value: p.id, label: `${p.name} (${p.type})` })),
433→          ]}
434→          onChange={(v) => handleUpdate({ sourceRefId: v || null })}
435→        />
436→      )}
437→      {viewport.sourceView === 'sketch_part_list' && (
438→        <>
439→          <SelectInput
440→            label="Object"
441→            value={viewport.sourceObjectId || ''}
442→            options={[
443→              { value: '', label: 'No object filter' },
444→              ...objects.map((object) => ({ value: object.id, label: object.name })),
445→            ]}
446→            onChange={(v) => handleUpdate({ sourceObjectId: v || null, sourceRefId: v || viewport.sourceRefId || null })}
447→          />
448→          <SelectInput
449→            label="Assembly"
450→            value={viewport.sourceObjectId ? '' : (viewport.sourceRefId || '')}
451→            options={[
452→              { value: '', label: 'All Parts' },
453→              ...assemblies.map((a) => ({ value: a.id, label: a.name })),
454→            ]}
455→            onChange={(v) => handleUpdate({ sourceRefId: v || null, sourceObjectId: null })}
456→          />
457→        </>
458→      )}
459→      <NumberInput label="Scale" value={viewport.scale || 100} suffix=":1" onChange={(v) => handleUpdate({ scale: v })} />
460→      <SelectInput
461→        label="Caption"
462→        value={viewport.captionPosition || 'below'}
463→        options={[
464→          { value: 'below', label: 'Below' },
465→          { value: 'above', label: 'Above' },
466→        ]}
467→        onChange={(v) => handleUpdate({ captionPosition: v })}
468→      />
469→      <button className={styles.duplicateBtn} onClick={handleDelete} style={{ color: '#c44' }}>
470→        Remove Viewport
471→      </button>
472→    </>
473→  );
474→}
