476→function ObjectProperties({ object, project, dispatch, editorDispatch }) {
477→  const template = object.templateType ? getTemplate(object.templateType) : null;
478→  const [pendingParams, setPendingParams] = useState(
479→    object.templateParams ? { ...object.templateParams } : {}
480→  );
481→
482→  const handleNameChange = (name) => {
483→    dispatch({ type: 'OBJECT_UPDATE', object: { id: object.id, name } });
484→  };
485→
486→  const handleParamChange = (key, value) => {
487→    setPendingParams((prev) => ({ ...prev, [key]: value }));
488→  };
489→
490→  const handleApply = () => {
491→    dispatch({ type: 'TEMPLATE_REGENERATE', objectId: object.id, params: pendingParams });
492→  };
493→
494→  const handleDetach = () => {
495→    dispatch({ type: 'OBJECT_DETACH', objectId: object.id });
496→  };
497→
498→  const handleGenerateSheet = () => {
499→    const sheet = generateObjectSheet(project, object.id);
500→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
501→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
502→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
503→  };
504→
505→  return (
506→    <div className={styles.panel}>
507→      <div className={styles.header}>Object</div>
508→      <div className={styles.content}>
509→        <TextInput label="Name" value={object.name} onChange={handleNameChange} />
510→
511→        <div className={styles.field}>
512→          <span className={styles.fieldLabel}>Template</span>
513→          <span className={styles.typeBadge}>{template?.label || object.templateType || object.category}</span>
514→        </div>
515→
516→        <div className={styles.fieldGroup}>
517→          <span className={styles.groupTitle}>Overall Dimensions</span>
518→          <div className={styles.fieldRow}>
519→            <NumberInput label="Width" value={object.dimensions?.width || 0} readOnly onChange={() => {}} />
520→            <NumberInput label="Depth" value={object.dimensions?.depth || 0} readOnly onChange={() => {}} />
521→            <NumberInput label="Height" value={object.dimensions?.height || 0} readOnly onChange={() => {}} />
522→          </div>
523→        </div>
524→
525→        {template && (
526→          <div className={styles.fieldGroup}>
527→            <span className={styles.groupTitle}>Parameters</span>
528→            <TemplateParamsForm
529→              parameters={template.parameters}
530→              values={pendingParams}
531→              onChange={handleParamChange}
532→            />
533→          </div>
534→        )}
535→
536→        {object.summary && (
537→          <div className={styles.field}>
538→            <span className={styles.fieldLabel}>Summary</span>
539→            <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{object.summary}</span>
540→          </div>
541→        )}
542→
543→        <div className={styles.field}>
544→          <span className={styles.fieldLabel}>Assemblies</span>
545→          <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{(object.assemblyIds || []).length}</span>
546→        </div>
547→
548→        <div className={styles.field}>
549→          <span className={styles.fieldLabel}>Parts</span>
550→          <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{(object.partIds || []).length}</span>
551→        </div>
552→
553→        {template && (
554→          <button className={styles.duplicateBtn} onClick={handleApply}>
555→            Apply Parameters
556→          </button>
557→        )}
558→        <button className={styles.duplicateBtn} onClick={handleGenerateSheet}>
559→          Generate Object Sheet
560→        </button>
561→        {object.editingPolicy === 'parametric' && (
562→          <button className={styles.duplicateBtn} onClick={handleDetach} style={{ color: '#888' }}>
563→            Detach to Custom Assemblies
564→          </button>
565→        )}
566→      </div>
