 3→export default function TemplateParamsForm({ parameters, values, onChange }) {
 4→  return (
 5→    <div className={styles.fieldGroup}>
 6→      {parameters.map((param) => {
 7→        if (param.type === 'boolean') {
 8→          return (
 9→            <label key={param.key} className={styles.field}>
10→              <span className={styles.fieldLabel}>{param.label}</span>
11→              <input
12→                type="checkbox"
13→                checked={!!values[param.key]}
14→                onChange={(e) => onChange(param.key, e.target.checked)}
15→                style={{ accentColor: 'var(--color-workspace-sketch, #B8860B)' }}
16→              />
17→            </label>
18→          );
19→        }
20→
21→        const step = param.type === 'integer' ? 1 : (param.step || 1);
22→        return (
23→          <label key={param.key} className={styles.field}>
24→            <span className={styles.fieldLabel}>{param.label}</span>
25→            <div className={styles.fieldInput}>
26→              <input
27→                type="number"
28→                value={Math.round(values[param.key] ?? param.default)}
29→                min={param.min}
30→                max={param.max}
31→                step={step}
32→                onChange={(e) => {
33→                  const v = param.type === 'integer' ? parseInt(e.target.value, 10) : parseFloat(e.target.value);
34→                  if (!isNaN(v)) onChange(param.key, v);
35→                }}
36→                className={styles.numberInput}
37→              />
38→              {param.suffix && <span className={styles.suffix}>{param.suffix}</span>}
39→            </div>
40→          </label>
41→        );
42→      })}
43→    </div>
44→  );
45→}
