 48→    case 'cutout':
 49→    case 'hole':
 50→      return createPartPlaceHandler({ ...ctx, partType: activeTool });
 51→    case 'dimension':
 52→      return createDimensionHandler(ctx);
 53→    case 'select':
 54→    default:
 55→      return createSketchSelectHandler(ctx);
 56→  }
 57→}
